import {{ Injectable }} from '@nestjs/common';
import {{ MigrationService }} from './models/migration.model';
import {{ MigrationServiceRepository }} from './repositories/migration.repository';

@Injectable()
export class MigrationServiceService {{
  constructor(
    private readonly repository: MigrationServiceRepository,
  ) {{}}

  async findAll(): Promise<MigrationService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<MigrationService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<MigrationService>): Promise<MigrationService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<MigrationService>): Promise<MigrationService> {{
    return this.repository.update(id, data);
  }}
}}
